  `service_areas` text COLLATE utf8mb4_unicode_ci,
  `rope_support` tinyint(1) NOT NULL DEFAULT '0',
  `gondola_supported` tinyint(1) NOT NULL DEFAULT '0',
  `branco_supported` tinyint(1) NOT NULL DEFAULT '0',
  `aerial_platform_supported` tinyint(1) NOT NULL DEFAULT '0',
  `official_url` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `areas` json DEFAULT NULL,
  `achievements_summary` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `safety_items` json DEFAULT NULL,
  `is_featured` tinyint(1) NOT NULL DEFAULT '0',
  `sort_order` int NOT NULL DEFAULT '0',
  `security_points` text COLLATE utf8mb4_unicode_ci,
  `performance_summary` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `strength_tags` text COLLATE utf8mb4_unicode_ci,
  `recommend_score` int NOT NULL DEFAULT '0',
  `safety_score` int NOT NULL DEFAULT '0',
  `performance_score` int NOT NULL DEFAULT '0',
  `review_score` decimal(3,1) NOT NULL DEFAULT '0.0',
  `review_count` int NOT NULL DEFAULT '0',
  `email_quote` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `phone` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `address_text` text COLLATE utf8mb4_unicode_ci,
  `max_floor` int DEFAULT NULL,
  `emergency_supported` tinyint(1) NOT NULL DEFAULT '0',
  `insurance` tinyint(1) NOT NULL DEFAULT '0',
  `price_note` text COLLATE utf8mb4_unicode_ci,
  `rank_score` int NOT NULL DEFAULT '0',
  `published_at` datetime DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `service_categories` json DEFAULT NULL COMMENT 'サービスカテゴリ: window, exterior, inspection, sign, other',
  `tags` json DEFAULT NULL COMMENT '会社の特徴・強みタグ（柔軟に追加可能）',
